var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이런 뒷골목 술집에서 아티팩트를 거래한다니, 역시 인간들은 음험하다니까.","JPN":"こんな裏路地の酒場でアーティファクトを取引するなんて、やっぱり人間は陰険だね～","ENG":"Trading Artifacts in a back alley bar? I knew humans were sneaky.","TWN":"居然在這種小巷的酒吧交易人造神器，人類果然陰險。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"모든 인간들이 학회처럼 음험하다는 편견은 버려 주세요.","JPN":"すべての人間が学会のように陰険だという偏見は捨ててください。","ENG":"Please do not think that all people are insidious like the Society.","TWN":"請放下所有人都像學會一樣陰險的偏見。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"애초에 정말 여기가 맞는지도 확인되지 않았습니다.","JPN":"そもそも、本当にここで合っているかどうかも定かではありません。","ENG":"We do not even know if we are at the right location in the first place.","TWN":"一開始就沒有得到確認，是不是真的在這裡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"안심하세요, 부학회장님. 종교학부장님께서 가르쳐 주신 곳인 걸요.","JPN":"ご安心ください、副学会長様。宗教学部長様が教えてくださった場所ではないですか。","ENG":"Don't worry, ma'am. The Dean of Religion pointed us here.","TWN":"你放心，副學會長。這裡是宗教學院院長告訴我的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다들 뱃속에 뱀 두어 마리는 키우고 사는 족속들이니 그렇죠.","JPN":"みんな腹の中にヘビの2、3匹は飼ってるような人たちですからね。","ENG":"I am concerned because they all have a hidden agenda that they are not telling us about.","TWN":"我只是不放心那些口蜜腹劍的傢伙們而已。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님은 어떻게 생각하세요?","JPN":"社長はどうお考えですか？","ENG":"What do you think, Boss?","TWN":"老闆是怎麼想的？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 의심은 좋은 습관이라네. 하물며 학회 같은 곳에서라면 더더욱.","JPN":"はは、疑うのはいい習慣だ。学会のようなところなら尚更さ。","ENG":"Haha, having doubts is a good habit. Especially if you're dealing with people from the Society.","TWN":"哈哈，疑心病是個好習慣。在學會這樣的地方尤其如此。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 당장은 다른 도리가 없지 않나. 최대한 신중하게 접근할 수밖에.","JPN":"だが今は別の手がないだろう。できるかぎり慎重に接近するしかあるまい。","ENG":"But, for the time being, we have no choice but to proceed with caution.","TWN":"但是眼下也沒有別的辦法。就只能儘量謹慎對待。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 그렇죠? 그럼 우선 주변을 탐문한 뒤에…….","JPN":"やはりそうですわよね？　それではまず周辺で聞き込みをして……","ENG":"I knew it. Then we should first investigate our surroundings, and–","TWN":"果然是吧？那我們先在周圍調查一番，然後……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"됐네요. 그냥 가서 확인해 보면 되는 거 가지고.","JPN":"いいよ、別に。直接行って確認してみればいいじゃん。","ENG":"Why do that? Let's just go in see what's happening over there.","TWN":"好了，直接進去確認就行了，有什麼可說的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"편하게 돌아다닐 입장이 아니니까요. 남들 눈에 띌수록 골치 아파집니다.","JPN":"気楽に歩き回れる状況ではありません。目立つと困りますわ。","ENG":"Because we are not in a position to be roaming around freely. The more eyes there are on us, the more problematic it becomes.","TWN":"因為我們現在不方便隨便走動。被別人發現就麻煩了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그렇다면 내가 날아가서 슬쩍 보고 오는 건 어때? 어차피 주위는 조용하잖아. ","JPN":"じゃあ、アタシが飛んでいって、そっと見てくるのはどう？　どうせこの辺りは静かなんだし。 ","ENG":"Then how about I swoop in and take a little peek? There's no one around us anyway. ","TWN":"那我飛過去偷看怎麼樣？反正周圍都沒什麼人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큰일날 소리 마세요. 남들 눈에 띄면 어쩌려고요?","JPN":"無茶なこと言わないでください。目立ったらどうするつもりですか？","ENG":"Are you serious?! What if someone sees you?","TWN":"你可不要說這種話。如果被人發現怎麼辦？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"히힛. 내가 하루 이틀 날아 본 줄 알아? 들켜도 카운터라고 변명하면 그만이지.","JPN":"へへっ。アタシの飛行経験を無視しないでよね。バレてもカウンターだって言い訳すればいいし。","ENG":"Teehee! It's not my first time flying, you know? If I get caught, I'll just say I'm a Counter.","TWN":"嘻嘻，你以為我第一天在天上飛嗎？如果被人發現，只要說自己是制裁者就行了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"여기서 기다리고 있어! 눈 깜빡할 사이에 다녀올 테니까!","JPN":"ここで待ってて！　あっという間に行ってくるから！","ENG":"Just wait here! I'll be back in a flash!","TWN":"你們在這裡等著！我一會兒就回來！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잠깐만요! 당신도 상태가……!","JPN":"待ってください！　あなたの具合も……！","ENG":"Wait! But you are...!","TWN":"等等！你的狀態也……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가 버렸네. 하아, 골치야…….","JPN":"行ってしまったわ。はあ、頭痛い……","ENG":"And there she goes... Ooh, my head...","TWN":"飛走了呢，唉，真讓人頭痛……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"날아다니는 루나 님은 꼭 기름등에 달려드는 나방 같네요.","JPN":"飛びまわっているルナ様は、まるでオイルランタンに惹き寄せられる蛾のようですね。","ENG":"When Ms. Luna flies, she looks like a moth attracted to a flame.","TWN":"飛來飛去的露娜，看起來好像撲向火的飛蛾啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"불길한 얘기 마세요, 실키. 꼭 불 붙어서 추락할 것 같잖아요.","JPN":"不吉なこと言わないでください、シルキー。火がついて落ちそうではないですか。","ENG":"Please do not say that, Sylkie. It sounds like she will catch flame and fall.","TWN":"不要說這種不吉利的話，思琪。聽起來就像她會渾身著火墜落一樣。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 아무리 단순해도 그림자인데 쉽게 당할 리 없죠.","JPN":"そうですわ。いくら単純でもシャドウですし、簡単にやられるわけがありませんわ。","ENG":"Right. She is a Shadow after all. I am certain she will not go down so easily.","TWN":"是啊，即便看起來再怎麼單純，她也是暗影，不會輕易受傷的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"앗! 총소리……!","JPN":"あっ！　銃声……！","ENG":"Huh? A gunshot...?!","TWN":"啊！槍聲……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나를 노리고 있어요! 설마 매복이 있었던 건가요?","JPN":"ルナさんを狙っています！　まさか待ち伏せでしょうか？","ENG":"They are gunning at Luna! Were they waiting for us?","TWN":"目標是露娜！難道有埋伏？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"떨어졌어요! 총에 맞으셨나 봐요!","JPN":"落ちました！　銃に撃たれたみたいです！","ENG":"She fell! I think she got shot!","TWN":"掉下來了！她好像中槍了！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부학회장니이이이임!!","JPN":"副学会長おおおお！！","ENG":"Vice Presidenttttt!!","TWN":"副學會長！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"다른 일당이 있나 보군! 어서 찾아!","JPN":"他の仲間がいるみたいだぞ！　早く探せ！","ENG":"She has friends nearby! Find them!","TWN":"看來還有別的同夥！快找出來！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아아아아…… 정마알…….","JPN":"はああああ……もぉぉ……","ENG":"*Sigh...* Oh dear...","TWN":"啊啊啊啊……真是的……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하고 싶은 말이 많다는 건 알겠네만, 일단 참게나.","JPN":"言いたいことがたくさんあるのはわかるが、ここは抑えるんだ。","ENG":"I know you have an earful to say, but now's not the time.","TWN":"我知道你有很多話要說，不過先忍忍吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"그래서 내가 그 호라이즌이란 계집애 머리통에 총을 들이대고 한마디 했지.","JPN":"それで、俺があのホライズンって女の頭に銃を突きつけてこう言ったんだ。","ENG":"So I pointed my gun straight at that Horizon girl's face and said this.","TWN":"所以我用槍抵著地平線那個臭丫頭的腦袋，說過這句話。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"<color=#ffd34c>지갑을 열래, 아니면 머리 뚜껑을 열래?</color>","JPN":"<color=#ffd34c>財布を開けるか、それとも頭のフタを開けるか？</color>","ENG":"<color=#ffd34c>Do you wanna open your wallet, or do you want me to open your head?</color>","TWN":"<color=#ffd34c>你是要交出錢包，還是要腦袋開花？</color>"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"그랬더니 그 빚쟁이가 사색이 돼서 살려 달라고 싹싹 빌더라니까?","JPN":"そしたらあの借金持ち、真っ青になって命乞いしやがってさ。","ENG":"That's when that loan shark's face got pale as a ghost and started begging for mercy!","TWN":"結果那個欠債的人嚇得臉色鐵青，哀求我饒命？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"허세 작작 부려. 몇 년 전에 넌 안전 장치도 풀 줄 몰랐잖아.","JPN":"はったりもいい加減にしろよ。何年か前のお前なんて、安全装置も外せなかっただろ。","ENG":"Pfft! As if! You didn't even know how to take the safety off until a few years ago!","TWN":"少吹牛了。幾年前你連安全裝置都打不開。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"늬들 뉴스를 믿냐? 개머리판으로 한 대 치면 질질 짤 거 같은 계집애가 그딴 짓을 벌였다고?","JPN":"おめえら、あのニュース信じてんのか？　銃床で一発殴れば、めそめそ泣きそうな女があんなことするか？","ENG":"But you really believe the news? That all of that was caused by a girl who looks like she'd ball her eyes out if you hit her with the stock of your gun?","TWN":"你們相信新聞嗎？感覺用槍托敲一下都會哭出來的臭丫頭做出了那種事？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"그거 다 관리국이 제프티 묻어 버리려고 퍼뜨린 헛소문이야. 넷튜브에서 봤다니까.","JPN":"そんなの全部管理局がジェフティを崩すためにばら撒いたウワサなだろ。ネットチューブで見たぜ。","ENG":"That was just the Administration spreading wild rumors to bury Jehuty. I saw it on NetTube!","TWN":"那些都是管理局為了瓦解傑夫堤集團而散佈的謠言。我在網路上看到過。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그런가? 상당히 흥미로운 가설이로군, 젊은 친구.","JPN":"ほう？　とても興味深い仮説だな。","ENG":"You think so? That's a rather interesting hypothesis, young man.","TWN":"是嗎？這個假設很有意思啊，年輕人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"응? 뭐야, 이 할아범은?","JPN":"ああ？　何だ、このジジイは。","ENG":"Huh? Who's this old geezer?","TWN":"嗯？什麼啊，你這個老頭？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"어이, 이 가게는 오늘 장사 안 해. 술 마시고 싶으면 다른 데 알아 봐.","JPN":"おい、この店は今日は休みだ。酒飲みたけりゃ他を当たれ。","ENG":"Hey, we're closed for today. Get your booze on somewhere else.","TWN":"喂，這家店今天不營業。想喝酒的話去別的地方吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"오해하지 말게. 나는 금주가라네.","JPN":"誤解しないでほしいな。私は酒を飲まない。","ENG":"No need for booze. I don't drink.","TWN":"別誤會，我不是來喝酒。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"여기엔 그저 의뢰한 물건을 받으러 왔을 뿐이야. 자네 이야기는 더 자세히 듣고 싶네만.","JPN":"ここにはただ依頼したものを取りに来ただけだ。君の話はもっと詳しく聞きたいがね。","ENG":"I am here, however, to receive a package from a client. I would love to hear more about your story, but...","TWN":"我只是來這裡拿委託的東西。所以也是順便聽你們聊天。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"잠깐, 댁이 그 <color=#ffd34c>교수</color>야?","JPN":"待った、おたくがあの<color=#ffd34c>教授</color>なのか？","ENG":"Wait a minute, you're the <color=#ffd34c>Professor</color>?!","TWN":"等等，你就是那個<color=#ffd34c>教授</color>？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"우리더러 아티팩트를 빼돌리라고 했던?","JPN":"俺たちにアーティファクトを横流ししろと言った、あの？","ENG":"The one who asked us to smuggle out the Artifact?","TWN":"讓我們偷走人造神器的那個？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그렇다네. 직접 대면하는 건 이번이 처음이었지, 아마.","JPN":"正解だ。直接会うのはたぶん今度が初めてだったな。","ENG":"Indeed. This is our first time meeting face-to-face, is it not?","TWN":"是的。這應該是我們第一次見面。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"허 참. 요즘 시대에 누가 편지로 의뢰를 하나 했더니. 생긴 거랑 어울리게 노시네.","JPN":"ハッ。今時手紙で依頼するなんてどんな奴かと思ったら。いかにもって感じだぜ。","ENG":"Hah! I was wondering who sends a handwritten letter in this day and age. It suits you, old man.","TWN":"天啊，我還在想，這年頭還有誰會寫信委託任務。你的行事風格跟你的長相確實很搭。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"고리타분한 것에는 고리타분한 것에서만 읽어낼 수 있는 매력이 존재하지.","JPN":"古いものには古いからこそ読みとれる魅力がある。","ENG":"Old ways have a certain appeal that can only be found in them, no?","TWN":"老東西中，也有老東西獨特的魅力。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"편지지의 재질과 봉랍 방식에서 보낸 이의 취향을 유추해내는 것처럼 말이야.","JPN":"便箋の材質と封蝋方法から、差出人の趣味を推測できるようにな。","ENG":"Just like how you can infer the sender's taste by their choice of paper and waxing methods.","TWN":"就像從信紙的材質和封蠟方式中可以推測出寄信人的喜好一樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"그딴 복잡한 말은 혼자 하시지.","JPN":"小難しい話は一人でやってくれ。","ENG":"We don't care for that kinda stuff.","TWN":"那種複雜的哲理你還是自己說吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"어이, 물건 가져 와.","JPN":"おい、持って来い。","ENG":"Hey, bring that thing over here.","TWN":"喂，把東西拿過來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"선생이 부탁했던 물건이 나팔이었던가?","JPN":"先生が頼んだものはトランペットだっけか？","ENG":"The thing you asked for was a trumpet, right?","TWN":"先生委託的東西是小喇叭嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"오보에라네. 관악기라는 점은 둘 다 같군.","JPN":"オーボエだ。管楽器というところは合っているがな。","ENG":"An oboe. But you did get the wind instrument part correct.","TWN":"是雙簧管。不過二者都是管樂器這點是一樣的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"그래, 오보에. 이 케이스 안에 들어 있어. 확인해 봐.","JPN":"そう、オーボエ。このケースに入ってるぜ。確認してみな。","ENG":"Yeah, an oboe. It's in the case. Take a look if you want.","TWN":"嗯，雙簧管。就在這個盒子裡，你看看吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"밖이 소란스러운데, 자네 친구들이 사고를 친 것 아닌가?","JPN":"外が騒がしいが、君の友人が事故を起こしたのではないか？","ENG":"Sounds rather rowdy outside. Are your friends causing a scene out there?","TWN":"外面很吵，不會是你的朋友鬧事了吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"쳇. 늦게 온 주제에 뭐 그리 궁금한 게 많아. 물건 확인 안 할 거야?","JPN":"ちっ。遅れて来ておいて何がそんなに気になるんだ？　確認しねえのか？","ENG":"Tch! You have a lot of questions for someone who's late. Are you gonna check it or not?","TWN":"嘖，遲到這麼久，還問那麼多。你不先確認東西嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"잔금 못 주겠다는 헛소리만 지껄여 봐. 그 잘난 턱수염째로 주둥이를 날려 주지.","JPN":"残金払わねえとか言ってみろよ。そのお上品なあご髭ごと口が吹っ飛ぶかもな？","ENG":"And I dare you to say that you can't pay us. I'll blow your face apart along with that fancy beard.","TWN":"如果你敢說不願意付尾款那種廢話，信不信我拔光你的鬍子。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"매사에 상당히 예민하군. 혹시 복용하는 약이라도 있나?","JPN":"何事にも相当敏感だな。もしかして飲んでいる薬でもあるのか？","ENG":"You seem irritated by everything. Are you taking any medicine?","TWN":"對每件事都相當敏感呢。難道你經常服用藥物嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"편히 얘기해 보게. 자네 같은 치들의 정신 구조는 매번 흥미로워.","JPN":"気楽に話してみろ。君のような輩の精神構造は、いつも興味深い。","ENG":"You can tell me. I'm always interested in the mental model of you punks.","TWN":"沒事，你可以說出來的。因為我對你這種傢伙的精神結構很感興趣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"뭐야? 이 늙은이가……!","JPN":"んだと？　この老いぼれが……！","ENG":"What did you call me...?!","TWN":"什麼？你這老頭……！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"어이, 멈춰. 거래는 중지야.","JPN":"おい、待て。取引は中止だ。","ENG":"Hey, stop. The deal's off.","TWN":"喂，停下，交易中止。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"염탐하는 놈들이 있었어. 끌고 와.","JPN":"こっちを探ってるやつらがいた。連れて来い。","ENG":"We got some unwanted guests here today. Bring them in.","TWN":"有個人在鬼鬼祟祟，我把她抓過來了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음, 결국 보란 듯이 잡혀 버렸군.","JPN":"むむ、結局見事に捕まってしまったな。","ENG":"Hmm... So in the end, they got us, eh?","TWN":"呃，好像輕易就被抓住了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"초, 총 좀 치우면 안 돼? 나 지금도 뼈 사이에서 몇 발 덜그럭거리는데?","JPN":"じゅ、銃をどけてくれない？　アタシ、今も骨の間から何発かゴロゴロ音がしてるんだ。","ENG":"C-could you point that somewhere else? I still have a few bullets rattling between my bones, you know!","TWN":"槍…槍能收起來嗎？現在我的骨頭中間還有幾發子彈在哐哐作響呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으윽……! 이 손 못 놔요?!","JPN":"ううっ……！　放しなさい！！","ENG":"Ngh...! I demand you let go of me!","TWN":"呃呃……！還不快點把手拿開？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"정중하게 대해 주세요! 부학회장님은 몸이 편찮으시다고요!","JPN":"丁重に扱ってください！　副学会長様はお体の具合がよくないんです！","ENG":"Please be respectful! The Vice President is already in pain!","TWN":"請小心點！副學會長的身體不舒服！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아윽!?","JPN":"あうっ！？","ENG":"Augh?!","TWN":"呃唔！？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실키! 당신들 어린애한테 무슨 짓이야?!","JPN":"シルキー！　あなたたち、子どもになんてことをするの！？","ENG":"Sylkie! You dare lay hands on a child?!","TWN":"思琪！你們在對小孩子做什麼？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"저 헐벗은 꼬마랑 시끄러운 년은 카운터야.","JPN":"あの半裸のガキと、うるさい女はカウンターだ。","ENG":"That loud one and the one that's barely dressed are Counters.","TWN":"那個衣衫襤褸的小鬼和吵鬧的傢伙是制裁者。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"늙은이, 꼬리를 달고 온 건가? 제대로 해명 안 하면 거래가 아니라 댁 목숨부터 신경 써야 할 거야.","JPN":"ジジイ、仲間を連れてきてたのか？　納得のいく説明しねえと、取引どころかおたくの命の心配をしなきゃならなくなるぜ。","ENG":"Are these your lackeys, old man? You'd better explain quickly, or your concern won't be just about the deal falling through.","TWN":"老頭，你被人追蹤了？要是解釋不清楚，那就不只是不能交易的問題，而是得關心下你自己老命了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……교수님?","JPN":"……きょ、教授？","ENG":"Professor?","TWN":"……教授？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양, 제가 여기 있는지는 어떻게 알고 오셨습니까?","JPN":"マクレディーさん、私がここにいるとどうしてわかったのですか？","ENG":"Ms. MacCready, how did you know I would be here?","TWN":"麥克蕾蒂，你是怎麼知道我在這裡的？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조, 종교학부장에게 들었어요. 고고학부장이 아티팩트를 거래한다고…….","JPN":"しゅ、宗教学部長から聞きましたわ。考古学部長がアーティファクトを取引すると……","ENG":"W-we heard from Dean of Religion that Dean of Archeology would be dealing an Artifact here...","TWN":"我聽考…考古學院院長說的。考古學院院長說你要交易人造神器……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"흐음. 안 본 사이에 질 나쁜 친구들과 친해지셨군요. 유감입니다.","JPN":"ふむ。見ない間に質の悪い人と親しくなったようですね。残念です。","ENG":"Hmm... It's a shame that you've made some bad friends since the last time I saw you.","TWN":"嗯嗯，許久不見，你交了壞朋友呢，真可惜。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"이봐, 늙은이. 한가하게 서로 안부나 물을 처지야?","JPN":"おい、ジジイ。のんびり挨拶なんかしてる場合か？","ENG":"Old man, I don't think you understand the situation you're in.","TWN":"喂，老頭，你現在還有心思閒聊呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"꼬리를 달고 왔다는 건 꿍꿍이가 있었다는 뜻이지.","JPN":"仲間を連れてきたってことは、なんか裏があるってことだろ。","ENG":"Bringing your lackeys here means there's something you haven't told us yet, no?","TWN":"帶著人過來，說明你心裡有鬼。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"이렇게 된 이상 죄다 토해낼 때까지 울고불고 해도 소용없을 거야.","JPN":"こうなった以上、全部吐くまでは泣きつかれても容赦しないぜ。","ENG":"I'll make you sing like a bird and tell me everything.","TWN":"既然如此，在你說出所有真相之前，不管你怎麼哀求都沒有用。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"총은 잠깐 치워 둬. 금방 죽여 버리면 재미없어.","JPN":"銃は下ろせ。すぐ殺しちまうとつまんねえんだろ。","ENG":"Whoa, easy. Put the gun down. Where's the fun when we just kill them now?","TWN":"把槍收起來。這麼快就殺掉他就沒意思了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"어…… 너…… 왜…….","JPN":"あ……？　お前……なんで……","ENG":"Huh? Hey... Why are y–","TWN":"啊……你……為什麼……"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"저, 저 새끼가! 너 갑자기 미쳤어!?","JPN":"あ、あの野郎！　頭おかしくなったのか！？","ENG":"What the hell?! Are you insane?!","TWN":"那…那小子！你突然瘋了嗎！？"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"방해해서 죄송합니다, 교수님. 다치실 수 있을 것 같아 쏘고 말았습니다.","JPN":"邪魔をして申し訳ございません、教授。怪我されるかと思い、撃ってしまいました。","ENG":"Apologies for the interruption, Professor. I was worried you might get hurt, so I took action.","TWN":"對不起，打擾到你了，教授。因為感覺你可能會受傷，我就開槍射殺了。"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"일이 틀어졌으니 할 수 없지. 다들 처리하게.","JPN":"こうなっては仕方ない。全部処理しろ。","ENG":"The deal is off, so no matter. Take care of them for me.","TWN":"事情搞砸了呢，沒辦法，都處理掉吧。"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실키, 루나! 엎드려요!","JPN":"シルキー、ルナさん！　伏せなさい！","ENG":"Sylkie, Luna! Get down!!","TWN":"思琪，露娜！快趴下！"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"죽어! 이 배신자 놈들! 아악!","JPN":"死ね！　この裏切り者め！　ぐはっ！","ENG":"Die, you traitors!! Arrgh!","TWN":"去死！你們這些叛徒！啊啊！"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"저 빌어먹을 늙은이에게 붙은 거냐?! 얼마 받고……","JPN":"あのクソジジイについたのか！？　いくらもらって……","ENG":"How much did he pay you to switch sides, huh?!","TWN":"你們搭上那個該死的老頭了嗎？！收了多少錢……"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"컥!","JPN":"かはっ！","ENG":"Kuh!","TWN":"唔！"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"미안하네. 자네들에겐 아티팩트의 입수 과정을 자세히 설명해 줄 지능이 없어 보이더군.","JPN":"悪いな。君たちにはアーティファクトを入手した経路を詳しく説明できる知能がなさそうだったのでね。","ENG":"I'm sorry. But you all seemed too incoherent to explain the process of obtaining the Artifact in detail.","TWN":"抱歉，以你們的智商，我應該不需要詳細說明入手人造神器的過程。"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L23_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그래서 감시역을 몇 명 붙여 뒀네. 지금 같은 만약의 상황에도 대비할 겸 말이야.","JPN":"何人か監視役をつけておいたんだ。今のように、万が一の事態の備えも兼ねてね。","ENG":"So, I had a few men keep an eye on you. Also, in case something like this happened.","TWN":"所以就派了幾個監工，也是為了防止出現這種突發情況。"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"컥…… 허억…… 이, 이 개자식…….","JPN":"くっ……はあ……こ、このクソ野郎……","ENG":"Kuh... *Gasp* You... son of a...","TWN":"咳……咳咳……你、你這個王八……"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"괜찮습니까, 맥크레디 양?","JPN":"大丈夫ですか？　マクレディーさん。","ENG":"Are you all right, Ms. MacCready?","TWN":"你沒事吧，麥克蕾蒂？"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"교수님…… 아니, 당신은 대체…….","JPN":"教授……いいえ、あなたはいったい……","ENG":"Professor... Is that really you...?","TWN":"教授……不，你究竟是……"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"설명은 우선 자리를 옮긴 뒤에 드리겠습니다.","JPN":"説明は場所を移してからにしましょう。","ENG":"I'll explain after we move to a safer place.","TWN":"先換個地方我再跟你解釋。"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"정보가 한 번 새어나간 이상, 일이 복잡해질 것 같군요.","JPN":"一度情報が漏れてしまった以上、面倒なことになりそうです。","ENG":"Things will become more complicated now that the information has been leaked once.","TWN":"既然資訊已經洩露，事情就變得複雜了。"},"stage":{"bg":"CLUB1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};